"use strict";
$(document).bind("contextmenu", function (a) {
  a.preventDefault();
});
$(document).keydown(function (a) {
  if (123 === a.which) return !1;
});
var queryString = window.location.search,
  urlParams = new URLSearchParams(queryString),
  city = urlParams.get("city"),
  type = urlParams.get("type");
load(city, type);

function load(a, d) {
  var c = new XMLHttpRequest();
  a = "city=" + a + "&type=" + d;
  c.open("POST", "api/infoplaces.php", !0);
  c.setRequestHeader("Content-type", "application/x-www-form-urlencoded");
  c.onreadystatechange = function () {
    if (4 == c.readyState && 200 == c.status) {
      var b = JSON.parse(c.responseText);
      $("#tipo").html(b.typename);
      $("#nome").html(b.city);
      $("title").html("PedeJ\u00e1 - " + b.city + " - " + b.typename);
      if ("avaliable" == b.status) {
        categories(city, type);
        b = b.places;
        b.sort((a, b) => a.ordem - b.ordem);
        let g;
        let h, l, k;
        if (1 <= b.length)
          for (let e = 0; e < b.length; e++) {
            if (1 == b[e].status) {
              if (2 == b[e].method)
                (g = "PedeJ\u00e1"),
                  (h =
                    '<a class="linktorest" href="https://pedeja.pt/estabelecimento.html?type=' +
                    type +
                    "&city=" +
                    city +
                    "&estab=" +
                    b[e].id +
                    '">');
              else {
                g = "PedeJ\u00e1";
                var f = b[e].code;
                h =
                  '<a class="linktorest" href="https://www.foodbooking.com/ordering/restaurant/menu?restaurant_uid=' +
                  f +
                  '&client_is_mobile=true">';
              }
              l = "</a>";
              k = "on";
            } else
              (g = 2 == b[e].status ? "Sobrecarregado" : "Indispon\u00edvel"),
                (l = h = ""),
                (k = "off");
            f = "";
            for (let m = 0; m < b[e].categories.length; m++)
              f = f + " cat" + JSON.parse(b[e].categories[m]);
            $("#places").append(`
                    <div class="col-6 col-xs-6 col-sm-4 col-md-4 col-lg-3 col-xl-3 filterDiv ${f}" >
                    ${h}
                    <div class="card mb-3">
                        <img src="https://pedeja.pt/assets/img/thumbnails/${city}/${b[e].id}.png" class="card-img-top ${k}" alt="${city}">
                        <div class="card-body">
                          <p class="card-text row">
                            <small class="text-muted col-12  col-md-7"><span class="material-icons inline-icon"><span class="material-icons-outlined">info_outline</span></span>   ${b[e].info}</small>
                            <small class="text-muted col-12  col-md-5  estado ${k}"><span class="material-icons inline-icon"><span class="material-icons-outlined">radio_button_checked</span></span>   ${g}</small></p>
                        </div>
                      </div>
                      ${l}
                    </div>
                  `);
          }
        else window.location.href = "https://pedeja.pt/404.html";
      } else window.location.href = "https://pedeja.pt/404.html";
    }
  };
  c.send(a);
}

function categories(a, d) {
  var c = new XMLHttpRequest();
  a = "city=" + a + "&type=" + d;
  c.open("POST", "api/infocategories.php", !0);
  c.setRequestHeader("Content-type", "application/x-www-form-urlencoded");
  c.onreadystatechange = function () {
    if (4 == c.readyState && 200 == c.status) {
      let b = JSON.parse(c.responseText).categories;
      if (1 <= b.length) {
        for (let f = 0; f < b.length; f++)
          $("#tags-menu").append(
            `<button class="button inline-icon" onclick="filterSelection('cat${b[f].id}')" ><img class="iconsvg" style="height: 30px; margin-right: 8px;" src="https://pedeja.pt/assets/img/icons/${b[f].slug}.svg" type="image/svg+xml">${b[f].name}</button>`
          );
        filterSelection("todos");
        $("#tags-menu").css("opacity", "100%");
      } else $("#tags-menu").css("display", "none"), filterSelection("todos");
    }
  };
  c.send(a);
}
const slider = document.querySelector(".scroll");
let isDown = !1,
  startX,
  scrollLeft;
slider.addEventListener("mousedown", (a) => {
  isDown = !0;
  slider.classList.add("active");
  startX = a.pageX - slider.offsetLeft;
  scrollLeft = slider.scrollLeft;
});
slider.addEventListener("mouseleave", () => {
  isDown = !1;
  slider.classList.remove("active");
});
slider.addEventListener("mouseup", () => {
  isDown = !1;
  slider.classList.remove("active");
});
slider.addEventListener("mousemove", (a) => {
  isDown &&
    (a.preventDefault(),
    (slider.scrollLeft = scrollLeft - (a.pageX - slider.offsetLeft - startX)));
});

function filterSelection(a) {
  var d;
  var c = document.getElementsByClassName("filterDiv");
  "todos" == a && (a = "");
  for (d = 0; d < c.length; d++)
    w3RemoveClass(c[d], "show"),
      -1 < c[d].className.indexOf(a) && w3AddClass(c[d], "show");
}

function w3AddClass(a, d) {
  var c = a.className.split(" ");
  var b = d.split(" ");
  for (d = 0; d < b.length; d++)
    -1 == c.indexOf(b[d]) && (a.className += " " + b[d]);
}

function w3RemoveClass(a, d) {
  var c = a.className.split(" ");
  var b = d.split(" ");
  for (d = 0; d < b.length; d++)
    for (; -1 < c.indexOf(b[d]); ) c.splice(c.indexOf(b[d]), 1);
  a.className = c.join(" ");
}
for (
  var btnContainer = document.getElementById("tags-menu"),
    btns = btnContainer.getElementsByClassName("button"),
    i = 0;
  i < btns.length;
  i++
)
  btns[i].addEventListener("click", function () {
    var a = document.getElementsByClassName("active");
    a[0].className = a[0].className.replace(" active", "");
    this.className += " active";
  });
window.addEventListener("pageshow", function (a) {
  (a.persisted ||
    ("undefined" != typeof window.performance &&
      2 === window.performance.navigation.type)) &&
    window.location.reload();
});
